#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int r1,w1,c1,r2,w2,c2;
        scanf("%d %d %d", &r1, &w1, &c1);
        scanf("%d %d %d", &r2, &w2, &c2);
        int cnt = 0;
        if(r1 > r2) cnt++;
        if(w1 > w2) cnt++;
        if(c1 > c2) cnt++;
        putchar(cnt >= 2 ? 'A' : 'B');
        if(T) putchar('\n');
    }
    return 0;
}

